INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('immigration-1aab856d-moex-00020', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-0e6322b2', 'sub-immigration-1aab856d-01', NULL, 'single_choice', '入出國及移民法於112年6月28日修正公布，內政部移民署爰訂定「外國人申請永久居留無不 良素行認定標準」，下列得認定無不良素行之情形，何者錯誤？', '["緩起訴處分或緩刑期滿未經撤銷", "罰金執行完畢", "拘役執行完畢逾3年", "犯最重本刑為5年以下有期徒刑、拘役或罰金之罪，其行刑權時效完成逾3年"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:52+00:00", "source_pdf_sha1": "f309a77206ce", "answer_pdf_sha1": "8dae9df4e2a0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0714", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國土安全與移民政策(包括移民人權)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00021', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-0e6322b2', 'sub-immigration-1aab856d-01', NULL, 'single_choice', '有關應請求社工人員或相關專業人員協助鑑別疑似人口販運被害人之條件，「人口販運防制法施 行細則」第17條第3項明定4種情形之一時司法警察應請求協助，下列敘述何者錯誤？', '["疑似被害人情緒不穩，無法或難以配合司法警察進行詢問", "疑似被害人因精神障礙或其他心智缺陷致無法為完全陳述", "疑似被害人為未滿18歲之兒童或少年", "社工或相關專業人員要求"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:52+00:00", "source_pdf_sha1": "f309a77206ce", "answer_pdf_sha1": "8dae9df4e2a0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0714", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國土安全與移民政策(包括移民人權)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00022', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-0e6322b2', 'sub-immigration-1aab856d-01', NULL, 'single_choice', '近來國人因求職受騙遭販運至海外從事犯罪行為之案件頻傳，犯罪集團多以組織化分工，犯行橫 跨國內、國外，或有負責在國內招募有意至海外求職之國人者，或有負責安排受騙國人出境至海 外與集團接洽者，或有在海外強逼受騙國人從事犯罪，或對受騙國人進行性剝削，或有聽聞遭摘 賣器官者。下列有關112年6月14日修正、113年1月1日行政院公告施行之人口販運防制法 修法成果之敘述，何者錯誤？', '["犯罪集團所為犯行之行為地、結果地均在中華民國領域外者，不適用人口販運防制法第29條 性剝削、第30條和第31條勞動剝削、第32條摘除他人器官、第33條意圖剝削、第34條因 而致人於死或重傷者加重處罰等罪", "本次修法，增訂犯罪分子如剝削並利用被害人實行依我國法律有刑罰規定的行為，處 1 年以 上、7年以下有期徒刑", "本次修法，意圖剝削，以招募、運送、容留等不法手段從事販運行為時，則採取事前防堵的刑 事處罰機制，也可處5年以下有期徒刑，而對於未滿18歲者，更可處7年以下有期徒刑，以 嚇阻人口販運的惡行", "利用被害人從事犯罪活動並加以剝削，亦屬於勞動剝削樣態，因此本次修法增訂意圖剝削或故 意使被害人「實行依我國法律有刑罰規定的行為」，納入勞動剝削範圍，同時增訂相關刑事處 罰要件"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:52+00:00", "source_pdf_sha1": "f309a77206ce", "answer_pdf_sha1": "8dae9df4e2a0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0714", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國土安全與移民政策(包括移民人權)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00023', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-0e6322b2', 'sub-immigration-1aab856d-01', NULL, 'single_choice', '依據112年12月28日修訂之人口販運被害人及疑似人口販運被害人安置服務管理規則，被害人 及疑似被害人有下列情形之一者，得不予機構式安置服務；安置後發現者，得暫不予機構式安置 服務，下列敘述何者錯誤？', '["毒品成癮或精神狀態明顯異常", "喧嘩、爭吵、飲酒、賭博、破壞毀損公物、傷害他人及違反管理命令等行為", "經依本法第12條指定傳染病篩檢有傳染之虞", "有自殺、自殘或殺人、傷人之虞"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:52+00:00", "source_pdf_sha1": "f309a77206ce", "answer_pdf_sha1": "8dae9df4e2a0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0714", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國土安全與移民政策(包括移民人權)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00024', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-0e6322b2', 'sub-immigration-1aab856d-01', NULL, 'single_choice', '為增進移民事務及打擊人口販運之實質合作，我國於2018年5月施行國際刑事司法互助法，截 至2023年止，我國已與12國簽署司法互助條約（協定），對於打擊人口販運犯罪亦發揮實質助 益。12國已簽署司法互助之國家中包含下列那一個國家？', '["美國", "日本", "越南", "印尼"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:52+00:00", "source_pdf_sha1": "f309a77206ce", "answer_pdf_sha1": "8dae9df4e2a0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0714", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國土安全與移民政策(包括移民人權)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00025', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-0e6322b2', 'sub-immigration-1aab856d-01', NULL, 'single_choice', '報載一外國人於2023年來臺期間非法工作遭地方政府勞動局裁處，因而被禁止入境臺灣數年。 有關禁止外國人入國作業規定，下列敘述何者正確？', '["從事與申請停留、居留目的不符之活動，而經驅逐出國或限令出國者，禁止入國至少5年", "外國人非法工作者，禁止入國3年", "申請來我國之目的作虛偽之陳述或隱瞞重要事實者，禁止入國至少3年", "因非法工作經禁止入國，其親生子女為有戶籍國民、合法居留之無戶籍國民或永久居留者，得 申請不予禁止入國"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:52+00:00", "source_pdf_sha1": "f309a77206ce", "answer_pdf_sha1": "8dae9df4e2a0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0714", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國土安全與移民政策(包括移民人權)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00026', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-0e6322b2', 'sub-immigration-1aab856d-01', NULL, 'single_choice', '近日在臺已取得戶籍之大陸配偶陸續接獲內政部移民署通知繳附喪失原籍證明，內政部移民署 說明：因兩岸關係是以單一戶籍為有序交流之依據，臺灣地區人民不得在大陸地區設有戶籍或 領用大陸地區護照，以避免雙重身分而造成權利義務重疊或衝突。臺灣地區人民如在大陸地區 設有戶籍或領用大陸地區護照者，其在臺之相關權利義務受影響，下列敘述何者正確？', '["可在臺灣地區行使選舉、罷免、創制、複決等權利", "可擔任軍職、公職", "戶政機關註銷其臺灣地區之戶籍登記", "臺灣地區人民身分所負之責任及義務，因而喪失或免除"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:52+00:00", "source_pdf_sha1": "f309a77206ce", "answer_pdf_sha1": "8dae9df4e2a0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0714", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國土安全與移民政策(包括移民人權)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00027', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-0e6322b2', 'sub-immigration-1aab856d-01', NULL, 'single_choice', '進入臺灣地區之大陸地區人民，如有事實足認為有危害國家安全或社會安定之虞者，內政部移民 署得逕行強制出境，或限令其於10日內出境，逾限令出境期限仍未出境，內政部移民署得強制 出境，但強制已取得居留或定居許可之大陸地區人民出境前應召開審查會，下列得不經審查會之 情形，何者錯誤？', '["依其他法律規定限制出境", "有危害國家利益、公共安全、公共秩序或從事恐怖活動之虞，且情況急迫應即時處分", "以書面聲明放棄陳述意見", "自願出境"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:52+00:00", "source_pdf_sha1": "f309a77206ce", "answer_pdf_sha1": "8dae9df4e2a0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0714", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國土安全與移民政策(包括移民人權)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00028', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'essay', '2024 年 10 月間，滯留臺灣的西班牙籍男子奧納德，因在國外涉嫌詐
騙，為國際刑警組織紅色通報對象，經內政部移民署決議驅逐出境，
但出境過程一波三折。奧納德向臺北高等行政法院聲請提審，請問臺
北高等行政法院裁定的法理要點為何？又內政部移民署的辯護與說明
為何？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:52+00:00", "source_pdf_sha1": "ee1e44310058", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0609", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00029', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'essay', '甲男使用交友軟體結識 A女（二人皆已成年），某日甲於租屋處與 A 合
意發生性行為。甲趁 A矇眼替甲口交之際，在 A不知情之下偷偷打開手
機的錄影功能，錄下 A口交的影像，影像中由於A的眼睛及臉部輪廓被
衣物遮蔽，甲亦未露臉，因此皆無法辨識出影像中的人物是誰。甲後來
將該影像匿名上傳到色情網站上，為警查獲。甲辯稱當初拍攝口交影片
有經 A同意，然A於警詢時嚴詞否認知情，亦不同意拍攝。經檢察官起
訴，法院審理時，A因身心嚴重受創，經 A之社工轉陳 A不願意出庭，
並表示 A有自殘現象，唯恐再受2 次傷害，無法到庭陳述。請附理由詳
述：
甲的刑事責任為何？（15分）
法院審理時，能否以 A在司法警察面前的供述作為認定甲犯罪事實之
證據？（10分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:52+00:00", "source_pdf_sha1": "ee1e44310058", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0609", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL)
